CREATE TABLE IF NOT EXISTS "site_model_aliases" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "site_id" INTEGER NOT NULL, "source_model" TEXT NOT NULL, "alias_model" TEXT NOT NULL, "alias_key" TEXT NOT NULL, "enabled" BOOLEAN NOT NULL DEFAULT true, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("site_id") REFERENCES "sites"("id") ON DELETE CASCADE);
ALTER TABLE "token_routes" ADD COLUMN "route_kind" TEXT;
CREATE UNIQUE INDEX "site_model_aliases_site_alias_key_unique" ON "site_model_aliases" ("site_id", "alias_key");
CREATE INDEX "site_model_aliases_site_id_idx" ON "site_model_aliases" ("site_id");
ALTER TABLE "proxy_logs" ADD COLUMN "cache_read_tokens" INTEGER;
ALTER TABLE "proxy_logs" ADD COLUMN "cache_creation_tokens" INTEGER;
ALTER TABLE "proxy_logs" ADD COLUMN "prompt_tokens_include_cache" BOOLEAN;
